fit_stacked_es <- function(stacked_data, outcome, label) {
  if (nrow(stacked_data) == 0L) {
    cat("Skipping", label, "- no valid stacked cohorts.\n")
    return(NULL)
  }

  feols(
    as.formula(paste0(
      outcome,
      " ~ i(rel_year, treated, ref = -1) | unit_cohort_id + year^cohort_id"
    )),
    data = stacked_data,
    vcov = ~cz_aewr_region_fe
  )
}

