save_stacked_plot <- function(plot, filename) {
  if (is.null(plot)) {
    cat("Skipping", filename, "- no valid model.\n")
    return(invisible(NULL))
  }

  ggsave(
    path_figures(filename),
    plot,
    width = 8,
    height = 5,
    device = "png"
  )
}

